var e=[{id:`L2_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`이런, 어떻게든 포드를 요격했어야 했는데……!`,JPN:`まずい、ポッドを先に迎撃するべきでした……！`,ENG:`Drat, we should have intercepted the pod!`,TWN:`可惡！剛剛應該要攔截住逃生艙的……！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`ROJO_SCAVENGER_NULL_NULL`,text:{KOREA:`아직 일어설 수 있군. 카운터는 역시 튼튼해서 좋아.`,JPN:`まだ立ちあがるのか。やはりカウンターは頑丈でいい。`,ENG:`You can still stand. You Counters are so strong.`,TWN:`還站得起來呢！我就喜歡制裁者這麼有韌性！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`ROJO_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`SOLDIER_ALPHA_EXTRA_A`,text:{KOREA:`실장님한테서 떨어져라! 이 괴물 자식!`,JPN:`室長から離れろ！　この化け物め！`,ENG:`Get away from the Chief, you monster!`,TWN:`你這怪物！給我離室長遠一點！！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`SOLDIER_ALPHA_EXTRA_A`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`SOLDIER_ALPHA_EXTRA_NULL`,text:{KOREA:`초, 총이 어째서 안 나가는 거지? 탄약은 아직……`,JPN:`じゅ、銃が発射できない？　弾切れでもないのに……`,ENG:`W-why can't I fire my gun? I still have enough ammo.`,TWN:`槍…槍怎麼無法發射？子彈還在……`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`SOLDIER_ALPHA_EXTRA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`ROJO_SCAVENGER_NULL_NULL`,text:{KOREA:`그 여자가 부리는 기생충이 어떻게 돼 먹은 물건인진 몰라도 효과 하난 확실하군.`,JPN:`あの女が操る寄生虫がどういう仕組みか知らないが、効き目は抜群だな。`,ENG:`I don't know what kind of parasites she's using, but they work like a charm.`,TWN:`那女人操控的寄生蟲效果真的很不錯呢！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`ROJO_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`ROJO_SCAVENGER_NULL_NULL`,text:{KOREA:`그러게 쓸데없이 복잡한 무기만 좋아하면 안 되지.`,JPN:`無駄に複雑な武器ばかり好むからそんな目にあうんだ。`,ENG:`This is why you shouldn't rely on complex weapons like that.`,TWN:`我說，怎麼可以只喜歡用那種複雜又沒用的武器呢！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`ROJO_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`총까지 먹통으로 만들다니…… 무슨 짓을 한 거지?`,JPN:`銃まで使えなくする……どういうことだ？`,ENG:`You've made our guns useless. What did you do?`,TWN:`竟然把槍變成廢鐵……你做了什麼？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`ROJO_SCAVENGER_NULL_NULL`,text:{KOREA:`글쎄? 지금 그게 중요한가?`,JPN:`さあな。今そんなことが大事か？`,ENG:`Well, is that really important right now?`,TWN:`妳說呢？現在這是重點嗎？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`ROJO_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`ROJO_SCAVENGER_NULL_NULL`,text:{KOREA:`먼저 안 오면 이쪽에서 간다.`,JPN:`かかってこないなら、こちらから行くぞ。`,ENG:`If you won't come, I'll come to you.`,TWN:`妳不過來的話我就過去囉！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`ROJO_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`큭……?!`,JPN:`くっ……！`,ENG:`Ugh!`,TWN:`咳……？！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`ROJO_SCAVENGER_NULL_NULL`,text:{KOREA:`이건…… 전자기 펄스?`,JPN:`これは……電磁パルス？`,ENG:`This is... an EMP?`,TWN:`這是…… 電磁脈衝？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`ROJO_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`함내 방송을 듣고 바로 달려왔어요. 다들 괜찮으세요?`,JPN:`艦内放送を聞いて参りました。皆さん大丈夫ですか？`,ENG:`I came as soon as I heard the alert. Are you okay?`,TWN:`我聽到艦隊的廣播後就立刻趕過來了，大家都沒事吧？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`아가씨!`,JPN:`お嬢様！`,ENG:`Miss Jia!`,TWN:`小姐！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`조심하세요! 저 자와 가까이 있으면 장비를 사용할 수 없습니다!`,JPN:`気をつけてください！　あの者の近くにいると装備を使用できません！`,ENG:`Watch out! Stay away from him, or you can't use your gear!`,TWN:`小心！和那傢伙靠太近的話，裝備會無法使用！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L33_1`,type:`dialog`,speaker:`ROJO_SCAVENGER_NULL_NULL`,text:{KOREA:`……오.`,JPN:`……おお。`,ENG:`Oh.`,TWN:`……哦！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`ROJO_SCAVENGER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};